/**
 * Searches for a product by name and returns its ingredient list if found.
 * @summary Look up a product by name to get its ingredients
 */
export const getProductLookupUrl = (params: ProductLookupParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/product-lookup?${stringifiedParams}`
    : `/api/product-lookup`;
};

